// Pull each upstream by name — $input.all() ordering is not guaranteed.
const now = new Date().toISOString();
function src(name) {
  try { return $(name).first().json || {}; } catch { return {}; }
}
const stripe   = src('Stripe charges (MTD)');
const etsy     = src('Etsy receipts (MTD)');
const gumroad  = src('Gumroad sales (MTD)');
const plausible = src('Plausible (MTD)');
const gsc      = src('Search Console (28d)');
const is       = src('Influencersoft stats');

// Money cache
const stripeData = Array.isArray(stripe.data) ? stripe.data : [];
const etsyResults = Array.isArray(etsy.results) ? etsy.results : [];
const gumroadSales = Array.isArray(gumroad.sales) ? gumroad.sales : [];
const stripeRev = stripeData.reduce((s,c) => s + ((c.amount_captured || 0) / 100), 0);
const etsyRev = etsyResults.reduce((s,r) => s + parseFloat(r.grandtotal?.amount_major || r.subtotal?.amount_major || 0), 0);
const gumroadRev = gumroadSales.reduce((s,r) => s + parseFloat(r.price || 0) / 100, 0);
const totalMtd = stripeRev + etsyRev + gumroadRev;
const burn = parseFloat($env.MONTHLY_BURN || '0');
const money = {
  generatedAt: now,
  yesterday: { revenue: 0, orders: 0, refunds: 0 },
  week:      { revenue: 0, orders: 0, refunds: 0 },
  mtd:       { revenue: totalMtd, orders: stripeData.length + etsyResults.length + gumroadSales.length, refunds: 0, burn: burn },
  channels: [
    { name: 'Stripe',  amount: stripeRev,  share: totalMtd > 0 ? stripeRev/totalMtd : 0,  orders: stripeData.length, refunds: 0 },
    { name: 'Etsy',    amount: etsyRev,    share: totalMtd > 0 ? etsyRev/totalMtd : 0,    orders: etsyResults.length, refunds: 0 },
    { name: 'Gumroad', amount: gumroadRev, share: totalMtd > 0 ? gumroadRev/totalMtd : 0, orders: gumroadSales.length, refunds: 0 }
  ],
  topSkus: [],
  killSkuCandidates: [],
  refundSpikes: []
};

// Traffic cache
const sessions = plausible.results?.pageviews?.value || 0;
const users = plausible.results?.visitors?.value || 0;
const traffic = {
  generatedAt: now,
  yesterday: { sessions: 0, users: 0 },
  week:      { sessions: 0, users: 0 },
  mtd:       { sessions, users },
  bySite: [
    { id: 'thestrledger', name: 'thestrledger.com', sessions, users, deltaPct14d: null }
  ],
  topSources: [],
  anomalies: []
};

// SEO cache
const gscRows = Array.isArray(gsc.rows) ? gsc.rows : [];
const impressions = gscRows.reduce((s,r) => s + (r.impressions || 0), 0);
const clicks = gscRows.reduce((s,r) => s + (r.clicks || 0), 0);
const ctr = impressions > 0 ? clicks / impressions : 0;
const avgPosition = gscRows.length > 0 ? gscRows.reduce((s,r) => s + (r.position || 0), 0) / gscRows.length : 0;
const seo = {
  generatedAt: now,
  gsc: { impressions, clicks, ctr, avgPosition, indexingErrors: 0 },
  cwv: { pagesGood: 0, pagesNeedsImprovement: 0, pagesPoor: 0, worstLcpMs: null, worstCls: null, worstInpMs: null },
  topQueries: gscRows.slice(0, 20).map(r => ({ query: r.keys?.[0] || '', impressions: r.impressions || 0, clicks: r.clicks || 0, position: r.position || 0, deltaPosition: 0 })),
  strikingDistance: gscRows.filter(r => (r.position || 0) >= 5 && (r.position || 0) <= 20).slice(0, 20).map(r => ({ query: r.keys?.[0] || '', position: r.position, impressions: r.impressions || 0 })),
  indexingIssues: []
};

// Contacts cache
const contacts = {
  generatedAt: now,
  list: {
    total: is.total || 0,
    new7d: is.new7d || 0,
    new7dDelta: is.new7dDelta || 0,
    engaged30d: is.engaged30d || 0,
    cold90d: is.cold90d || 0
  },
  funnel: Array.isArray(is.funnel) ? is.funnel : [],
  topSources: Array.isArray(is.topSources) ? is.topSources : [],
  health: is.health || { bounceRate: 0, unsubRate: 0, complaintRate: 0, avgOpen: 0, avgClick: 0 },
  sequences: Array.isArray(is.sequences) ? is.sequences : []
};

return [
  { json: { _path: 'money.json',    payload: money } },
  { json: { _path: 'traffic.json',  payload: traffic } },
  { json: { _path: 'seo.json',      payload: seo } },
  { json: { _path: 'contacts.json', payload: contacts } }
];
